func submissionAnswerDisplay(raw string) string {
	var value any
	if json.Unmarshal([]byte(raw), &value) != nil {
		return ""
	}
	switch typed := value.(type) {
	case []any:
		values := make([]string, 0, len(typed))
		for _, item := range typed {
			values = append(values, fmt.Sprint(item))
		}
		return strings.Join(values, ", ")
	default:
		return fmt.Sprint(value)
	}
}

func helpID(field db.FormField) string {
	return "help_" + field.PublicID
}

func fieldAttrs(field db.FormField) templ.Attributes {
	if field.HelpText.Valid {
		return templ.Attributes{"aria-describedby": helpID(field)}
	}
	return nil
}

